code = """import pandas as pd, json
cases = pd.DataFrame(var_call_8zU4WvRZkc530zIlnAXeS2m)
accounts = pd.DataFrame(var_call_FNH41COs933frZB51HCHbPUW)
accounts['clean_id'] = accounts['clean_id'].str.strip()
accounts['clean_id'] = accounts['clean_id'].str.replace('#','', regex=False)
cases['accountid_clean'] = cases['accountid'].str.strip().str.replace('#','', regex=False)
merged = cases.merge(accounts, left_on='accountid_clean', right_on='clean_id', how='left')
merged['createddate'] = pd.to_datetime(merged['createddate'])
merged['closeddate'] = pd.to_datetime(merged['closeddate'])
merged = merged.sort_values('createddate')
end_date = pd.Timestamp('2022-10-26')
start_date = end_date - pd.DateOffset(months=18)
mask = (merged['createddate'] >= start_date) & (merged['createddate'] <= end_date)
merged = merged[mask]
merged['closure_hours'] = (merged['closeddate'] - merged['createddate']).dt.total_seconds() / 3600.0
state_stats = merged.groupby('state')['closure_hours'].mean().dropna()
if state_stats.empty:
    result = json.dumps(None)
else:
    best_state = state_stats.sort_values().index[0]
    result = json.dumps(best_state)
print("__RESULT__:")
print(result)"""

